SELECT r.id AS requestId, r.status AS status, r.period AS period, r.price AS price, r.new_expiration_date AS newExpirationDate, r.processed_by AS processedBy, r.processed_at AS processedAt, t.id AS tenantId, t.tenant_type AS tenantType, t.owner_id AS ownerId, parent_t.code AS groupId, t.code AS companyCode, t.expiration_date AS expirationDate, DATEDIFF(t.expiration_date, CURDATE()) AS daysUntilExpiration, COALESCE(o.name, '') AS ownerName FROM tenant_auto_renew_request r INNER JOIN tenant t ON t.id = r.tenant_id LEFT JOIN tenant parent_t ON parent_t.id = t.parent_id LEFT JOIN owner o ON o.id = t.owner_id
AND r.status = #{status}
AND t.tenant_type = #{tenantType}
AND DATE(r.processed_at) >= #{dateFrom}
AND DATE(r.processed_at) <= #{dateTo}
AND DATEDIFF(t.expiration_date, CURDATE()) <= #{windowDays}
ORDER BY r.created_at DESC

SELECT COUNT(*)
FROM tenant_auto_renew_request r
INNER JOIN tenant t ON t.id = r.tenant_id


        AND r.status = #{status}


        AND DATEDIFF(t.expiration_date, CURDATE()) <= #{windowDays}


        AND t.tenant_type = #{tenantType}

SELECT COUNT(*)
FROM tenant_auto_renew_request r
INNER JOIN tenant t ON t.id = r.tenant_id
WHERE r.status = 'pending'
  AND t.tenant_type = #{tenantType}
  AND DATEDIFF(t.expiration_date, CURDATE()) <= #{windowDays}
